import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import "./AddEmployee.css";

const AddEmployee = () => {

  const { id } = useParams();     // <-- This detects EDIT mode
  const navigate = useNavigate();

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    gender: "",
    dob: "",
    maritalStatus: "",
    email: "",
    password: "",
    designation: "",
    department: "",
    salary: "",
    role: "",

    bankName: "",
    accountNumber: "",
    ifsc: "",

    qualification: "",
    university: "",
    passingYear: "",
  });

  // ---------------- LOAD EMPLOYEE WHEN EDIT ----------------
  useEffect(() => {

    if (!id) return;   // add mode

    const employees = JSON.parse(localStorage.getItem("employees")) || [];

    const found = employees.find(
      e =>
        String(e.id) === String(id) ||
        String(e.empId) === String(id)
    );

    if (found) {
      setEmployee(found);
    }

  }, [id]);


  // ---------------- HANDLE CHANGE ----------------
  const handleChange = (e) => {
    setEmployee({
      ...employee,
      [e.target.name]: e.target.value
    });
  };


  // ---------------- SAVE EMPLOYEE ----------------
  const handleSubmit = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const updatedEmployee = {
      ...employee,
      id: id ? Number(id) : Date.now(),

      // VERY IMPORTANT – THIS FIXES YOUR TABLE NAME ISSUE
      name: `${employee.firstName} ${employee.lastName}`.trim()
    };

    // EDIT MODE
    if (id) {
      employees = employees.map(emp =>
        String(emp.id) === String(id) ||
        String(emp.empId) === String(id)
          ? updatedEmployee
          : emp
      );
    }

    // ADD MODE
    else {
      employees.push(updatedEmployee);
    }

    localStorage.setItem("employees", JSON.stringify(employees));

    alert(id ? "Employee Updated Successfully!" : "Employee Added Successfully!");

    navigate("/dashboard/employee-details");
  };


  return (
    <div className="employee-form-container">
      <h2>{id ? "Edit Employee" : "Add Employee"}</h2>

      <form onSubmit={handleSubmit} className="employee-form">

        <h4>Personal Details</h4>

        <input
          name="firstName"
          placeholder="First Name"
          value={employee.firstName}
          onChange={handleChange}
        />

        <input
          name="lastName"
          placeholder="Last Name"
          value={employee.lastName}
          onChange={handleChange}
        />

        <input
          name="empId"
          placeholder="Employee ID"
          value={employee.empId}
          onChange={handleChange}
        />

        <select name="gender" value={employee.gender} onChange={handleChange}>
          <option>Gender</option>
          <option>Male</option>
          <option>Female</option>
        </select>

        <input
          type="date"
          name="dob"
          value={employee.dob}
          onChange={handleChange}
        />

        <select name="maritalStatus" value={employee.maritalStatus} onChange={handleChange}>
          <option>Marital Status</option>
          <option>Single</option>
          <option>Married</option>
        </select>

        <input
          name="email"
          placeholder="Email"
          value={employee.email}
          onChange={handleChange}
        />

        <input
          name="password"
          type="password"
          placeholder="Password"
          value={employee.password}
          onChange={handleChange}
        />

        <h4>Job Details</h4>

        <input
          name="designation"
          placeholder="Designation"
          value={employee.designation}
          onChange={handleChange}
        />

        <input
          name="department"
          placeholder="Department"
          value={employee.department}
          onChange={handleChange}
        />

        <input
          name="salary"
          placeholder="Salary"
          value={employee.salary}
          onChange={handleChange}
        />

        <select name="role" value={employee.role} onChange={handleChange}>
          <option>Role</option>
          <option>Employee</option>
          <option>Admin</option>
        </select>

        <button type="submit">
          {id ? "Update Employee" : "Save Employee"}
        </button>

      </form>
    </div>
  );
};

export default AddEmployee;
